var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"한참을 내려왔는데, 아직도 더 내려간다고?","JPN":"まだ降りるのか？","ENG":"How far does this lift go down? It feels like forever.","TWN":"咳，都下來半天了，還要往下走？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대체 몇 층을 내려가고 있는 거야?","JPN":"いったいどこまで降りるんだ？","ENG":"How many floors are left?","TWN":"到底要下多少層？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"혼란스럽겠지만 이제 몇 층을 내려왔는지 같은 건 중요하지 않네.","JPN":"混乱しているだろうが、そんなことはもう重要ではない。","ENG":"It might be confusing to you, but it doesn't matter how far we're going down.","TWN":"雖然很混亂，但是下到幾樓並不重要。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"워치를 확인해보게. 이곳은 현실세계가 아니거든.","JPN":"ウォッチを確認してみろ。ここは現実世界ではないのだ。","ENG":"Look at your Watch. This place isn't the Normalside.","TWN":"確認一下能量環吧，這裡可不是現世。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 정말로 이면세계잖아?","JPN":"なんだ、本当に裏世界じゃないか。","ENG":"Huh? We're really in the Counterside?","TWN":"什麼啊，竟然是異界。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CLOCK_02"},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래. <color=#ffd34c>맥크레디 포인트</color>에 대해서는 가르쳐 준 적 있지?","JPN":"ああ。<color=#ffd34c>マクレディーポイント</color>については教えたことがあるはずだ。","ENG":"Correct. I've told you about <color=#ffd34c>MacCready Point</color> before, right?","TWN":"沒錯。關於<color=#ffd34c>麥克蕾蒂領地</color>，有教過你吧？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"알고 있어. 학회장이 살고 있는 동네 아니야. 버뮤다 삼각지대 같은 거라면서?","JPN":"わかってる。学会長が住んでる街だろ？　バミューダトライアングルみたいなものだっけ？","ENG":"I know about that. It's where the President lives. Didn't you say that place was like the Bermuda Triangle?","TWN":"我知道，是學會長住的地方吧。聽說是類似於百慕達三角洲的地方？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아. 잘 기억하고 있구만.","JPN":"よし。ちゃんと覚えているな。","ENG":"Good. So you do remember.","TWN":"沒錯，你記得很清楚呢。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳 역시 여러 아티팩트를 공명시켜 만들어낸 특수한 공간이라고 생각하면 돼.","JPN":"ここもまた色々なアーティファクトを共鳴させて作り出した特殊な空間と思えばいい。","ENG":"Think of here as a special space created through resonating various Artifacts.","TWN":"你把這裡當成是多個人造神器共鳴而形成的特殊空間就好。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"일반적인 방법으로는 절대 접근이 불가능하지.","JPN":"一般的な方法では決して近づくことができないのだ。","ENG":"It's impossible to reach here using conventional methods.","TWN":"用一般的方法是絕對不可能接近的。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐 때문에 그런 짓을 하는 건데?","JPN":"なんのためにそんなことを？","ENG":"Why would someone go through all this hassle then?","TWN":"為什麼要那麼做？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"일종의 보험이랍니다, 물벼룩.","JPN":"ある種の保険ですわ、ミジンコ。","ENG":"It's a kind of insurance, Water Flea.","TWN":"這是一種保險，水蚤。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 우리가 향하는 곳은 최고 레벨의 아티팩트 보관실. 일명, <color=#ffd34c>성궤</color>라고 불리는 곳이죠.","JPN":"今私たちが向かっている場所は、最高レベルのアーティファクト保管室。別名、<color=#ffd34c>聖櫃</color>と呼ばれるところです。","ENG":"Where we are headed right now is the Artifact storage room of the highest level. Also known as the <color=#ffd34c>Ark of the Covenant</color>.","TWN":"我們現在要去的是最高級別人造神器的保管室，又名<color=#ffd34c>聖軌</color>。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그곳의 아티팩트는 절대로 적에게 넘어가서는 안 되는 물건들이에요.","JPN":"あそこのアーティファクトは決して敵に渡してはいけません。","ENG":"The Artifacts here must never be placed in the hands of our enemies.","TWN":"那裡的人造神器是絕對不能落入敵人手中的東西。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 본부가 점령당하면, 유일한 출입구인 차원 엘리베이터를 폭파시켜 성궤를 현실로부터 격리합니다.","JPN":"機関は本部が占領されると、唯一の出入口である次元エレベーターを爆破し、聖櫃を現実から隔離します。","ENG":"If the Institution's headquarters were to be taken over, the dimensional lift, which serves as the only entrance, would be obliterated, isolating the Ark of the Covenant from the Normalside.","TWN":"如果總部被佔領，機關就會炸毀唯一的出入口次元電梯，將聖軌與現世隔離。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아티팩트가 학회 손에 들어갈 바에는 아예 없애 버리는 편이 더 낫다는 뜻이야?","JPN":"アーティファクトが学会の手に渡るくらいなら、いっそ消した方がいいってことなのか？","ENG":"So it's better to get rid of the Artifacts than to have them in the hands of the Society?","TWN":"與其讓人造神器落入學會手中，還不如乾脆除掉對嗎？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"도착했군요. 성궤에 온 걸 환영합니다, 물벼룩.","JPN":"着きましたわ。聖櫃へようこそ、ミジンコ。","ENG":"We've arrived. Welcome to the Ark of the Covenant, Water Flea.","TWN":"到了，歡迎來到聖軌，水蚤。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리가 찾는 아티팩트는 이쪽이에요.","JPN":"私たちの探しているアーティファクトはこちらです。","ENG":"The Artifact we are looking for is over there.","TWN":"我們要找的人造神器在這邊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 이 <color=#ffd34c>방패</color>는?","JPN":"なんだ、この<color=#ffd34c>盾</color>は？","ENG":"Huh? What's this <color=#ffd34c>shield</color>?","TWN":"這個<color=#ffd34c>盾牌</color>是什麼？"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 방패를 감싸고 있는 사슬들은 설마……?","JPN":"待てよ、この盾に巻き付いている鎖は、まさか……？","ENG":"Wait a minute. Those chains wrapped around the shield... Are they...?","TWN":"等等，圍繞著盾牌的鐵鍊難道是……？"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이 가진 <color=#ffd34c>봉인 사슬</color>과 같은 것이죠.","JPN":"そう、あなたが持っている<color=#ffd34c>封印の鎖</color>と同じものです。","ENG":"They are the same as your <color=#ffd34c>Sealing Chain</color>.","TWN":"和你擁有的<color=#ffd34c>封印鎖鏈</color>是一樣的。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에 비밀 격리 시설에서 파편을 봉인하고 있는 사슬은 전부 이 방패에서 생성된 부산물에 불과하답니다.","JPN":"そもそも秘密隔離施設で破片を封印している鎖は、すべてこの盾から生成された副産物に過ぎません。","ENG":"First and foremost, the chains that seal the Fragments in the secret quarantine facilities are byproducts of this shield.","TWN":"最初在秘密隔離設施中，封印碎片的鐵鍊都是從這個盾牌生成的附屬品。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"봉인 사슬이…… 방패의 부산물이라고?","JPN":"封印の鎖が……盾の副産物だと？","ENG":"The Sealing Chain is... a byproduct of this shield?","TWN":"封印鎖鏈……是盾牌的附屬品？"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 이 방패만 있다면 사슬을 무한히 만들어 낼 수 있다는 뜻이야?","JPN":"じゃあ、この盾さえあれば無限に封印の鎖を作り出せるってことなのか？","ENG":"So you're telling me that I can infinitely create chains as long as I have this shield?","TWN":"那你的意思是說，只要有這個盾牌，就能無限生成鐵鍊？"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네, 이 방패는 사용자의 CRF를 사슬 형태로 물질화 하는 효과를 가지고 있어요.","JPN":"はい、この盾は使用者のCRFを鎖の形で物質化する能力を持っています。","ENG":"Yes. This shield has the ability to materialise the user's CRF into chains.","TWN":"是的，這個盾牌具有將使用者的CRF物質化為鐵鍊狀的效果。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"또한 사슬에 닿은 적의 힘이 강하면 강할수록 고중력을 가해서 움직임을 봉쇄하죠.","JPN":"また、鎖に触れた敵の力が強ければ強いほど、高重力を与えて動きを封じるのです。","ENG":"Also, the chains apply stronger gravitational pulls the stronger the enemy is, stopping them in their tracks.","TWN":"而且，碰到鐵鍊的敵人力量越強，就會施加越高的重力來封鎖其行動。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관이 구 관리국의 봉인 함선 없이, 가아그셰블라의 파편을 봉쇄할 수 있는 것 역시 이 아티팩트 덕분입니다.","JPN":"機関が旧管理局の封印艦船なしで、ガアグシェブラの破片を封鎖できるのもまた、このアーティファクトのおかげなのです。","ENG":"Without the Old Administration's sealing ship, the Institution was only able to seal the Fragments of Gha'agsheblah because of this Artifact.","TWN":"機關能夠在沒有舊管理局的封印艦船的情況下，封鎖加格舍夫拉的碎片，也是得益於這個人造神器。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"따라서 이 아티팩트야말로, 기관의 상징이자 존재 의의 그 자체.","JPN":"よって、このアーティファクトこそ機関の象徴であり、存在意義そのもの。","ENG":"Therefore, this Artifact serves as both a symbol and a source of significance for the Institution.","TWN":"因此，這個人造神器，才是機關的象徵和存在本身。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>대 신성 무장</color>, <color=#ffd34c>프리드웬</color>.","JPN":"<color=#ffd34c>対神聖武装</color>、<color=#ffd34c>プリドウェン</color>。","ENG":"<color=#ffd34c>Anti-Divinity Armament</color>, <color=#ffd34c>Prydwen</color>.","TWN":"<color=#ffd34c>反神聖武裝</color>，<color=#ffd34c>普利多溫</color>。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대 신성 무장……?","JPN":"対神聖武装……？","ENG":"Anti-Divinity Armament...?","TWN":"反神聖武裝……？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대 신성 무장이란, 이름 그대로 <color=#ffd34c>신성</color>에 대항하는 무기.","JPN":"対神聖武装とは、その名のとおり<color=#ffd34c>神聖</color>に対抗する武器。","ENG":"An Anti-Divinity Armament is, as the name implies, a weapon against <color=#ffd34c>Divinity</color>.","TWN":"反神聖武裝，顧名思義就是對抗<color=#ffd34c>神聖</color>的武器。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"멸망해버린 세계들…… 클리포트의 마왕과 마지막까지 <color=#ffd34c>대적한 자</color>들이 남긴 유산입니다.","JPN":"滅亡してしまった世界たち……クリフォトの魔王と最後まで<color=#ffd34c>対敵した者</color>たちが残した遺産です。","ENG":"A legacy left by the <color=#ffd34c>opposers</color> of collapsed worlds... who fought against the Demon Lords of Qliphoth until the very end.","TWN":"是被毀滅的世界裡……和逆卡巴拉魔王抗爭到最後的<color=#ffd34c>敵對者</color>所留下的遺產。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"특히 클리파 타입에 대응하는 무장이라면, 해당 마왕 혹은 휘하의 사도에게 강력한 효과를 보이죠.","JPN":"特にクリファタイプに対応する武装があれば、その魔王、または旗下の使徒に強力な効果を発揮します。","ENG":"And if it's an armament that corresponds to a certain Qlipha-type, it shows great effectiveness against the specific Demon Lord or its Apostles.","TWN":"尤其是針對對付逆卡巴拉類型的武裝，對該魔王或麾下的使徒有強大的作用。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 부산물인 봉인 사슬조차 가아그셰블라의 파편에게 효과를 보이는 것처럼.","JPN":"その副産物である封印の鎖が、ガアグシェブラの破片に効果を発揮するように。","ENG":"Much like how the Sealing Chain, which is merely a byproduct, has an effect on the Fragments of Gha'agsheblah.","TWN":"就像連作為附屬的封印鎖鏈，也對加格舍夫拉的碎片有效一樣。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"현재까지 기관이 소재를 파악하고 있는 대 신성 무장은 네 종류.","JPN":"今まで機関が所在を把握している対神聖武装は4種類。","ENG":"As of now, the Institution knows the whereabouts of four Anti-Divinity Armaments.","TWN":"到目前為止，機關所掌握的反神聖武裝資訊有四。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"겨우살이 창. <color=#ffd34c>미스틸테인</color>.","JPN":"宿り木の槍。<color=#ffd34c>ミスティルテイン</color>。","ENG":"The Mistletoe Spear, <color=#ffd34c>Misteltein</color>.","TWN":"槲寄生之槍，<color=#ffd34c>米斯特丁</color>。"},"stage":{"bg":"MAINSTREAM_5302010","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"홍염의 지팡이. <color=#ffd34c>엘리노어 스태프</color>.","JPN":"紅炎の杖。<color=#ffd34c>エリノアスタッフ</color>。","ENG":"The Staff of Prominence, <color=#ffd34c>Eleanor Staff</color>.","TWN":"紅焰手杖，<color=#ffd34c>光明權杖</color>。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"신을 죽이는 검. <color=#ffd34c>울브즈베인</color>.","JPN":"神を殺す剣。<color=#ffd34c>ウルブズベイン</color>。","ENG":"The Godslayer, <color=#ffd34c>Wolvesbane</color>.","TWN":"弑神之劍，<color=#ffd34c>狼之災禍</color>。"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고…… 왕의 방패. <color=#ffd34c>프리드웬</color>.","JPN":"そして……王の盾。<color=#ffd34c>プリドウェン</color>。","ENG":"And lastly... the King's Shield, <color=#ffd34c>Prydwen</color>.","TWN":"還有……王的盾牌，<color=#ffd34c>普利多溫</color>。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 그 잘난 아티팩트만 잔뜩 모으면 마왕을 쓰러트릴 수 있다는 뜻이야?","JPN":"じゃあ、そのすごいアーティファクトをたくさん集めれば、魔王を倒せるってことなのか？","ENG":"Then, we can defeat the Demon Lord if we just keep gathering Artifacts?","TWN":"那麼，只要能湊夠這些人造神器，就能打倒魔王？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물벼룩다운 발상이네요.","JPN":"ミジンコらしい発想ですわね。","ENG":"What a water flea-like thing to say.","TWN":"不愧是水蚤能想出來的想法。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대 신성 무장은 어디까지나 마왕과 대적하기 위한 퍼즐 조각 중 하나일 뿐이에요.","JPN":"対神聖武装はあくまでも魔王と敵対するための一つのピースに過ぎません。","ENG":"Anti-Divinity Armaments are merely a piece of the puzzle to fight the Demon Lords.","TWN":"反神聖武裝只不過是用來對付魔王的拼圖碎片之一。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"애초에 아티팩트가 제대로 된 힘을 발휘하기 위해서는 적합한 사용자가 필요합니다.","JPN":"そもそもアーティファクトがちゃんとした力を発揮するためには、適合する使用者が必要ですわ。","ENG":"Furthermore, for Artifacts to unleash their true potential, there must be a suitable user.","TWN":"從一開始，人造神器需要有合適的使用者才能真正發揮作用。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"적합한 사용자?","JPN":"適合する使用者？","ENG":"A suitable user?","TWN":"合適的使用者？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기관에게 있어서 <color=#ffd34c>버넷</color>이 특별한 존재라고 했던 게…….","JPN":"機関にとって<color=#ffd34c>バーネット</color>が特別な存在だって言うのは……","ENG":"The reason you said that <color=#ffd34c>Burnetts</color> are special to the Institution is...","TWN":"所以對機關來說，<color=#ffd34c>伯內特</color>是特別的存在……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이제서야 눈치챈 모양이군요.","JPN":"やっと気付いたようですね。","ENG":"I see you have caught on.","TWN":"你現在才看出來嗎。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대 신성 무장을 다루기 위해서는 무장의 원래 주인이었던 자와 직접적인 <color=#ffd34c>인과</color>의 연결이 필요해요.","JPN":"対神聖武装を扱うためには、武装の元所有者だった者と直接的な<color=#ffd34c>因果</color>の繋がりが必要なのです。","ENG":"In order to wield an Anti-Divinity Armament, there must be a direct <color=#ffd34c>causal</color> link with its original owner.","TWN":"想操控反神聖武裝，就需要與武裝的原主人有直接的<color=#ffd34c>因果</color>。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이를테면, 원래 주인과 혈연으로 이어진 관계…….","JPN":"たとえば、元所有者との血縁者……","ENG":"For instance, a relationship linked by the bloodline of the original owner...","TWN":"例如，與原主人有血緣關係……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"혹은 드물게도 평행 세계 상에서 동일한 인물로 추측되어 사용 가능한 경우가 있습니다.","JPN":"そしてごく稀にですが、平行世界上での同一人物と推測されて、使用できる場合もあります。","ENG":"Or on rare occasions, someone from a parallel universe assumed to be the same person can also wield it.","TWN":"或者，很罕見地在平行世界中被推測為同一人物，因此可以使用。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬 최강의 요원이자 당신의 할아버지, <color=#ffd34c>리암 버넷</color> 경처럼 말이에요.","JPN":"プリドウェン最強エージェントでありあなたのお爺さん、<color=#ffd34c>リアム・バーネット</color>卿のように。","ENG":"Just like Sir <color=#ffd34c>Liam Burnett</color>, Prydwen's best agent who is also your grandfather.","TWN":"就像普利多溫的最強特工，你的爺爺，<color=#ffd34c>連恩·伯內特</color>卿一樣。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 할배가?","JPN":"俺のお爺さんが？","ENG":"My grandfather?","TWN":"我的爺爺？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대 신성 무장, 프리드웬은 생전 버넷 경이 다루던 방패입니다.","JPN":"対神聖武装、プリドウェンは生前のバーネット卿が扱っていた盾です。","ENG":"The Anti-Divinity Armament Prydwen was the shield your grandfather used when he was alive.","TWN":"反神聖武裝——普利多溫是伯內特卿生前所使用的盾牌。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"카멜롯 전대 시절부터 그는 이 방패와 함께 수없이 많은 전설을 남겼다고 하죠.","JPN":"キャメロット戦隊時代から、彼はこの盾と共に数多くの伝説を残したとされています。","ENG":"It is said that he created countless legends with this shield since the Camelot Division days.","TWN":"從卡梅羅戰隊時期，他就和這把盾牌一起留下了無數個傳說。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고…… 그가 죽은 지금, 프리드웬을 다룰 수 있는 사람은 이제 두 사람뿐.","JPN":"そして……彼が亡くなった今、プリドウェンを扱える人はあと二人だけ。","ENG":"But... he's dead now. So there are only two people who can wield Prydwen.","TWN":"還有……在他去世的現在，能操控普利多溫的就只有二個人。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷의 이름을 이어받은 로버트 버넷과 로이 버넷, 당신들이죠.","JPN":"バーネットの名を受け継いだロバート・バーネットとロイ・バーネット、あなたたちですわ。","ENG":"The ones who carry on the Burnett name. Robert Burnett and you, Roy Burnett.","TWN":"繼承了伯內特之名的羅伯特·伯內特和羅伊·伯內特，你們二個人。"},"stage":{"bg":"PRYDWEN_05","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 먼저 방패를 계승한 로버트는 책임을 져버리고 도망쳤어요.","JPN":"ですが先に盾を継承したロバートは、責任に背き逃げだしました。","ENG":"However, Robert, who was supposed to succeed the shield, refused to take on the responsibility and fled.","TWN":"但是，首先繼承起盾牌的羅伯特卻拋棄責任逃跑了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다른 사람은 짊어지고 싶어도, 짊어질 수조차 없는 막대한 책임을 방기한 채 말이죠.","JPN":"他の人が背負いたくても背負えない、大いなる責任を放棄して。","ENG":"Abandoning the huge responsibility that others cannot bear even if they want to.","TWN":"他把別人想扛卻也扛不起的巨大責任拋在腦後。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"만약 나도 프리드웬을 물려받지 않겠다고 하면 기관은 어쩔 생각이야?","JPN":"もし俺もプリドウェンを受け継がないと言ったら、機関はどうするんだ？","ENG":"What would the Institution do if I also said I didn't want to inherit Prydwen?","TWN":"如果我說，我也不想繼承普利多溫，機關會怎麼做？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"책임으로부터 도망칠 생각이라면 말리지는 않겠어요.","JPN":"責任から逃げるつもりなら、止めはしませんわ。","ENG":"If you choose to run away from your responsibility, we will not stop you.","TWN":"如果想逃避責任的話，我不會勸阻你。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그 경우, 우리는 당신이 낳은 자식에게 그 책임을 요구하게 될 겁니다.","JPN":"ですがその場合、私たちはあなたの子孫にその責任を要求することになるでしょう。","ENG":"However, in that case, we will have to ask your children to take on the responsibility.","TWN":"但若是真的發生那種情況，我們會要求你的子嗣承擔起這個責任。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"마왕으로부터 세계의 멸망을 막기 위해서.","JPN":"魔王による、世界の滅亡を止めるために。","ENG":"The responsibility of preventing the Demon Lord from destroying this world.","TWN":"為了阻止世界因魔王滅亡。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모든 특별함에는 그 책임이 따르기 마련이랍니다.","JPN":"すべての特別な者にはそれ相応の責任がついて来るものなのです。","ENG":"Everything exceptional comes at a cost.","TWN":"所有其特別之處都伴隨著它的責任。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 노블레스 오블리주…….","JPN":"だから、ノブレス・オブリージュ……","ENG":"That is why it is called noblesse oblige...","TWN":"所謂貴族，貴族……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"세계를 위해 부디 그 책무를 다하도록 하세요, 로이 버넷.","JPN":"世界のためにその責務を果たしなさい、ロイ・バーネット。","ENG":"So, Roy Burnett. Take on the responsibility for the world.","TWN":"為了世界，這就是你所要盡到的責任，羅伊·伯內特。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"으음? 본부로부터 단방향 통신?","JPN":"ん？　本部からの一方向通信？","ENG":"Mm? A one-way communication from HQ?","TWN":"嗯？從總部發來的單向通訊？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"여왕 폐하로부터의 직통 라인이라고……?","JPN":"女王陛下からの直通ラインだと……？","ENG":"It's a direct line from Her Majesty herself...?","TWN":"來自女王陛下的直撥通訊……？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨, 말씀 중에 죄송하지만 이걸 좀 봐주십시오!","JPN":"お嬢様、お話し中申し訳ありませんが、こちらをご覧ください！","ENG":"My lady, I'm sorry to cut you off but you must see this!","TWN":"小姐，很抱歉打斷你，請看一下這個！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"여왕 폐하로부터 발송된 긴급 암호 메시지입니다!","JPN":"女王陛下から発信された緊急暗号メッセージです！","ENG":"It is an encrypted urgent message from the Queen herself!","TWN":"是女王陛下發送的緊急加密資訊！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"여왕 폐하께서?","JPN":"女王陛下が？","ENG":"From the Queen?","TWN":"女王陛下？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 홍차 폭탄? 표정이 왜 그래?","JPN":"どうした、紅茶爆弾？　何て顔してんだよ。","ENG":"What's wrong, Tea Bomb? Why do you look so grim?","TWN":"怎麼了，紅茶炸彈？表情這麼凝重？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모건, 차원 엘리베이터를 기동시켜주세요.","JPN":"モーガン、次元エレベーターを起動してください。","ENG":"Morgan, please get the dimensional lift ready.","TWN":"摩根，請啟動次元電梯。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제임스 교수가 수용된 왕립교정국이 정체불명의 세력에 의해 공격받고 있습니다.","JPN":"ジェームス教授が収容された王立矯正局が、得体の知れない勢力によって攻撃されています。","ENG":"The Royal Correctional Service, where Professor James is imprisoned, is under attack by unknown forces.","TWN":"關押詹姆斯教授的王室矯正局正在受到不明勢力的攻擊。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};